+#[derive(Clone)]
+struct CellData {
+    kind: u8,
+    char_code: u32,
+    grapheme: Vec<u8>,
+    fg: u32,
+    bg: u32,
+    attrs: u32,
+}
+
+impl Default for CellData {
+    fn default() -> Self {
+        Self {
+            kind: 0,
+            char_code: 0,
+            grapheme: Vec::new(),
+            fg: ftui_render::cell::PackedRgba::WHITE.0,
+            bg: ftui_render::cell::PackedRgba::TRANSPARENT.0,
+            attrs: 0,
+        }
+    }
