+        empty_checksum, EXPECTED_CHECKSUM_EMPTY_2X2,
+        "unexpected checksum for empty 2x2 grid"
+    );
+
+    let cell_a = CellData {
+        kind: 1,
+        char_code: 'A' as u32,
+        ..Default::default()
+    };
+    grid[0] = cell_a.clone();
+
+    let checksum0 = checksum_grid(&grid);
+    assert_eq!(
+        checksum0, EXPECTED_CHECKSUM_A_ONLY_2X2,
+        "checksum stability regression for frame 0"
+    );
+
+    let cell_b = CellData {
+        kind: 1,
+        char_code: 'B' as u32,
+        ..Default::default()
+    };
+    grid[1] = cell_b.clone();
