+    writeln!(
+        trace,
+        r#"{{"event":"frame","frame_idx":0,"cols":2,"rows":2,"payload_kind":"diff_runs_v1","payload_path":"frames/frame_0000.bin","checksum":"{:016x}"}}"#,
