+    let mut times = Vec::with_capacity(iters as usize);
+    let mut total_us: u128 = 0;
+    let mut last_tile_stats = None;
+
+    for _ in 0..iters {
+        let start = Instant::now();
+        diff.compute_dirty_into(old, new);
