+/// Writer wrapper that can count bytes written when enabled.
+struct CountingWriter<W: Write> {
+    inner: W,
+    count_enabled: bool,
+    bytes_written: u64,
+}
+
+impl<W: Write> CountingWriter<W> {
+    fn new(inner: W) -> Self {
+        Self {
+            inner,
+            count_enabled: false,
+            bytes_written: 0,
+        }
+    }
+
+    #[allow(dead_code)]
